  // Rodrigues AXIS-ANGLE rotation — precalc ONCE in <Shader_Init>, then apply in the function:
  //   <Shader_Init>:  gmt_precalcRodrigues(uVec3B);   // params = (azimuth, pitch, angle)
  //   in function:    gmt_applyRodrigues(p);
